  ('social-worker-moex-01701', 'social-worker', 'social-worker-moex-108-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '績效考核時出現考評者很容易因自己的某些缺點，而對受評者有相似的缺點卻不予理會，造成考 核失真的偏失，是指下列何者潛在效應？', '["盲點效應（blindness effect）", "自我相似效應（similar-to-me effect）", "對比效應（contrast effect）", "尖角效應（horn effect）"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:10+00:00", "source_pdf_sha1": "c9da933020f6", "answer_pdf_sha1": "1c177e8bc0cf", "source_family": "moex-gov-tw", "moex": {"exam_code": "108020", "c": "107", "s": "0603", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "108", "exam_name": "108年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
