  ('social-worker-moex-01704', 'social-worker', 'social-worker-moex-108-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '志願服務法中有關志願服務運用單位之職責，下列敘述何者錯誤？', '["志願服務運用單位不論自行或聯合方式召募志工，應將志願服務計畫公告", "志願服務運用單位應提供志工必要之資訊並指定專人負責志願服務之督導", "志願服務運用單位應對志工辦理教育訓練，包括如基礎訓練和特殊訓練", "志願服務運用單位的工作不論是否須具專業執照，只要是志工都可以擔任"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:10+00:00", "source_pdf_sha1": "c9da933020f6", "answer_pdf_sha1": "1c177e8bc0cf", "source_family": "moex-gov-tw", "moex": {"exam_code": "108020", "c": "107", "s": "0603", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "108", "exam_name": "108年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
